queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasGreen_Buildings ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Green_Buildings } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasGreen_Buildings ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Green_Buildings } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?address ?name WHERE {
  ?green_buildings_features a :Green_Buildings_Features .
  ?features a :Features .
  ?green_buildings_features p:hasFeatures ?features .
  ?green_buildings a :Green_Buildings .
  ?green_buildings_features p:hasGreen_Buildings ?green_buildings .
  ?green_buildings p:address ?address .
  ?features p:name ?name .
} }
}
